import { processQueue } from '../src/asyncQueue.mjs';

const assert = (c, m) => { if (!c) throw new Error(m); };

function delay(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

async function runTests() {
  // Test 1: processes items in sequential order
  const order = [];
  await processQueue(['a', 'b', 'c'], async (item) => {
    const delayMs = item === 'a' ? 30 : item === 'b' ? 10 : 20;
    await delay(delayMs);
    order.push(item);
    return item.toUpperCase();
  });
  assert(JSON.stringify(order) === JSON.stringify(['a', 'b', 'c']), 'Should process in order [a,b,c] but got ' + JSON.stringify(order));

  // Test 2: returns results in order
  const results = await processQueue([1, 2, 3], async (n) => {
    await delay(5);
    return n * 10;
  });
  assert(JSON.stringify(results) === JSON.stringify([10, 20, 30]), 'Results should be [10,20,30] but got ' + JSON.stringify(results));

  // Test 3: error in one item does not prevent others from running
  const processed = [];
  const results3 = await processQueue(['x', 'fail', 'z'], async (item) => {
    await delay(5);
    if (item === 'fail') {
      processed.push('fail-attempted');
      throw new Error('item failed');
    }
    processed.push(item);
    return item;
  });
  assert(processed.includes('x'), 'Should have processed x');
  assert(processed.includes('fail-attempted'), 'Should have attempted fail');
  assert(processed.includes('z'), 'Should have processed z even after error');

  // Test 4: results contain errors for failed items
  assert(results3[0] === 'x', 'First result should be x');
  assert(results3[1] instanceof Error, 'Second result should be an Error');
  assert(results3[2] === 'z', 'Third result should be z');

  // Test 5: empty array returns empty results
  const r5 = await processQueue([], async (item) => item);
  assert(JSON.stringify(r5) === JSON.stringify([]), 'Empty queue should return empty results');

  console.log('ALL TESTS PASSED');
}

runTests();
